export const getGetUserSegmentsUrl = () => {




  return `/api/analytics/user-segments`
}

/**
 * @summary User spending behavior segments
 */
export const getUserSegments = async ( options?: RequestInit): Promise<UserSegment[]> => {

  return customFetch<UserSegment[]>(getGetUserSegmentsUrl(),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetUserSegmentsQueryKey = () => {
    return [
    `/api/analytics/user-segments`
    ] as const;
    }


export const getGetUserSegmentsQueryOptions = <TData = Awaited<ReturnType<typeof getUserSegments>>, TError = ErrorType<unknown>>( options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getUserSegments>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetUserSegmentsQueryKey();



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getUserSegments>>> = ({ signal }) => getUserSegments({ signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getUserSegments>>, TError, TData> & { queryKey: QueryKey }
}

export type GetUserSegmentsQueryResult = NonNullable<Awaited<ReturnType<typeof getUserSegments>>>
export type GetUserSegmentsQueryError = ErrorType<unknown>


/**
 * @summary User spending behavior segments
 */

